# generate grid
grid = [[0]*9 for _ in range(12)]
# place 5-block at rows4-8 col2-6
for r in range(4,9):
    for c in range(2,7):
        grid[r][c] = 5
# place moved 1-block at row3 col2-6
for c in range(2,7):
    grid[3][c] = 1
# place bottom 1-block at row11 col2-6
for c in range(2,7):
    grid[11][c] = 1
for row in grid:
    print(row)
