```python
import numpy as np

# initialize zero grid
grid = np.zeros((10,10),int)
# pattern
pattern = np.array([[1,0,1],[0,1,0],[1,1,1]])
# stamps:
# color 7 at (2,1)
for dr in range(3):
    for dc in range(3):
        if pattern[dr,dc]==1:
            grid[2+dr,1+dc]=7
# color 8 at (7,4)
for dr in range(3):
    for dc in range(3):
        if pattern[dr,dc]==1:
            grid[7+dr,4+dc]=8

grid
```
